before_code:
library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

entity alu_unit is
    port (
        opcode : in std_logic_vector(3 downto 0);
        operand_a : in std_logic_vector(7 downto 0);
        operand_b : in std_logic_vector(7 downto 0);
        result : out std_logic_vector(7 downto 0)
    );
end entity alu_unit;

architecture rtl of alu_unit is
begin
    process(opcode) is
        variable temp : std_logic_vector(7 downto 0);
    begin
        case opcode is
            when "0000" => temp := operand_a and operand_b;
            when "0001" => temp := operand_a or operand_b;
            when "0010" => temp := operand_a + operand_b;
            when others => temp := (others => '0');
        end case;
        result <= temp;
    end process;
end architecture rtl;

